module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [7:0] mul_a_reg, mul_b_reg;
reg [2:0] mul_en_out_reg;
reg [15:0] mul_out_reg;

reg [15:0] temp [0:7];
reg [15:0] sum [0:7];

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_en_out_reg <= 0;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end

genvar i, j;
generate
    for (i = 0; i < 8; i = i + 1) begin : pp_gen_loop
        for (j = 0; j < 8; j = j + 1) begin : pp_gen_inner_loop
            assign temp[i][j] = mul_a_reg[j] & mul_b_reg[i];
        end
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        for (int k = 0; k < 8; k = k + 1) begin
            sum[k] <= 0;
        end
    end else if (mul_en_in) begin
        sum[0] <= {9'b0, temp[0]};
        sum[1] <= {8'b0, temp[1]} + {8'b0, sum[0][7:0]};
        sum[2] <= {7'b0, temp[2]} + {7'b0, sum[1][7:0]};
        sum[3] <= {6'b0, temp[3]} + {6'b0, sum[2][7:0]};
        sum[4] <= {5'b0, temp[4]} + {5'b0, sum[3][7:0]};
        sum[5] <= {4'b0, temp[5]} + {4'b0, sum[4][7:0]};
        sum[6] <= {3'b0, temp[6]} + {3'b0, sum[5][7:0]};
        sum[7] <= {2'b0, temp[7]} + {2'b0, sum[6][7:0]};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out_reg <= 0;
    end else if (mul_en_in) begin
        mul_out_reg <= {sum[7][7:0], sum[6][7:0], sum[5][7:0], sum[4][7:0], sum[3][7:0], sum[2][7:0], sum[1][7:0], sum[0][7:0]};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out <= 0;
    end else if (mul_en_out_reg[2]) begin
        mul_out <= mul_out_reg;
    end else begin
        mul_out <= 0;
    end
end

endmodule
